50	  title: string;
51	  type: string;
52	  phase: string;
53	}
54	
55	/**
56	 * Composed result returned by `composeShow(...)`. The cartograph doc's
57	 * fields land at the top level (so the response is recognizably the
58	 * companion doc); the underlying writ row sits nested under `writ` to
59	 * avoid id/timestamp field collisions (D8). The supplementary fields
60	 * (`parent`, `children`, `links`) drive the text-mode renderer.
