261	 * Build the JSON output shape per D8: `{ ...doc, writ: { ... } }`. Doc
262	 * fields land at the top level; writ-side fields stay nested to dodge
263	 * id/timestamp collisions.
264	 */
265	export function renderShowJson<TDoc extends Record<string, unknown>>(
