1	/**
2	 * vision-apply — on-disk vision authoring.
3	 *
4	 * Reads a vision authored on disk at
5	 * `<guildHome>/vision/<slug>/{vision.md, vision-metadata.yml}` and
6	 * snapshots it into the cartograph as a vision writ + companion
7	 * VisionDoc using a single code path for both first-time bootstrap and
8	 * Nth re-import. After first apply the sidecar gains a system-managed
9	 * `visionId` field that binds the on-disk directory to its cartograph
10	 * writ.
11	 *
12	 * The data flow is one-way: file → writ. Edits to the writ are not
13	 * propagated back to the file.
14	 *
15	 * The tool also writes a `SurveyorExt` priority-hint payload into
16	 * `writ.ext['surveyor']` per the future surveying-cascade contract. The
17	 * substrate consuming that slot ships in a separate commission; the
18	 * slot is inert until then. The slot is always written (even when the
19	 * payload is `{}`) — its presence marks the writ as processed by apply.
20	 */
21	
22	import { z } from 'zod';
23	import { readFile, writeFile, rename } from 'node:fs/promises';
24	import path from 'node:path';
25	import { parseDocument, isMap, type Document } from 'yaml';
26	import { guild } from '@shardworks/nexus-core';
27	import { tool } from '@shardworks/tools-apparatus';
28	import type { ClerkApi } from '@shardworks/clerk-apparatus';
29	import type { CartographApi, VisionDoc, VisionStage } from '../types.ts';
30	
31	/**
32	 * Plugin id used for the surveyor `ext` slot. The future
33	 * surveyor-apparatus commission will define its own constant; the
34	 * values agree because the brief fixes the string. Kept local to this
35	 * file to avoid exposing a public-API constant for a slot whose owner
36	 * does not yet exist.
37	 */
38	const SURVEYOR_PLUGIN_ID = 'surveyor';
39	
40	/**
41	 * Tight slug regex: lowercase letters/digits/hyphens/underscores, no
42	 * leading dot, no path separators, no `..`. Validated at the CLI
43	 * boundary so bad slugs fail loudly with a clear error rather than
44	 * surface a murkier path-resolution failure later.
45	 */
46	const SLUG_REGEX = /^[a-z0-9][a-z0-9_-]*$/;
47	
48	/**
49	 * Stage values accepted in the sidecar. The full VisionStage enum,
50	 * mirrored at the boundary so unknown stages fail loudly.
51	 */
52	const VISION_STAGES = ['draft', 'active', 'sunset', 'cancelled'] as const;
53	
54	/**
55	 * The sanctioned sidecar fields. Anything outside this set is logged as
56	 * a warning and ignored — preserves forward-compatibility while still
57	 * surfacing typos.
58	 */
59	const KNOWN_SIDECAR_KEYS = new Set([
60	  'title',
61	  'stage',
62	  'codex',
63	  'visionId',
64	  'severity',
65	  'deadline',
66	  'decay',
67	  'complexity',
68	  'resolution',
69	]);
70	
71	/**
72	 * Fixed mapping from sidecar `stage` to writ `phase`. Mirrors the
73	 * mapping cartograph.createVision uses internally for initial creation
74	 * and is reused on Nth-apply transitions.
75	 */
76	const STAGE_TO_PHASE: Record<VisionStage, 'new' | 'open' | 'completed' | 'cancelled'> = {
77	  draft: 'new',
78	  active: 'open',
79	  sunset: 'completed',
80	  cancelled: 'cancelled',
81	};
82	
83	/**
84	 * Stages that constitute a "stale binding" if the sidecar's bound writ
85	 * is in any of these phases. Per D5: all terminal phases plus missing.
86	 */
87	const TERMINAL_PHASES = new Set(['cancelled', 'completed', 'failed']);
88	
89	/**
90	 * Surveyor-slot payload assembled from CLI flags + sidecar values per
91	 * D10/D11. Fields that neither source supplied are omitted; the slot
92	 * is still written even when the payload is `{}`.
93	 */
94	interface SurveyorPayload {
95	  severity?: string;
96	  deadline?: string;
97	  decay?: string;
98	  complexity?: string;
99	}
100	
101	/**
102	 * Result of parsing the sidecar. Holds both the structured fields and
103	 * the original yaml `Document` so we can round-trip-write the visionId
104	 * back without losing comments and key order (D14).
105	 */
106	interface ParsedSidecar {
107	  doc: Document;
108	  title: string;
109	  stage: VisionStage;
110	  codex?: string;
111	  visionId?: string;
112	  severity?: string;
113	  deadline?: string;
114	  decay?: string;
115	  complexity?: string;
116	  resolution?: string;
117	}
118	
119	function readStringField(record: Record<string, unknown>, key: string): string | undefined {
120	  const value = record[key];
121	  if (value === undefined || value === null) return undefined;
122	  if (typeof value !== 'string') {
123	    throw new Error(`[vision-apply] sidecar field "${key}" must be a string (got ${typeof value}).`);
124	  }
125	  return value;
126	}
127	
128	function parseSidecar(raw: string, sidecarPath: string): ParsedSidecar {
129	  let doc: Document;
130	  try {
131	    doc = parseDocument(raw);
132	  } catch (err) {
133	    const msg = err instanceof Error ? err.message : String(err);
134	    throw new Error(`[vision-apply] failed to parse sidecar "${sidecarPath}": ${msg}`);
135	  }
136	
137	  if (!isMap(doc.contents)) {
138	    throw new Error(
139	      `[vision-apply] sidecar "${sidecarPath}" must be a YAML map at the top level.`,
140	    );
141	  }
142	
143	  const obj = (doc.toJS() ?? {}) as Record<string, unknown>;
144	  if (typeof obj !== 'object' || Array.isArray(obj)) {
145	    throw new Error(
146	      `[vision-apply] sidecar "${sidecarPath}" must be a YAML map at the top level.`,
147	    );
148	  }
149	
150	  const title = readStringField(obj, 'title');
151	  if (title === undefined || title === '') {
152	    throw new Error(
153	      `[vision-apply] sidecar "${sidecarPath}" is missing the required field "title".`,
154	    );
155	  }
156	
157	  const stage = readStringField(obj, 'stage');
158	  if (stage === undefined) {
159	    throw new Error(
160	      `[vision-apply] sidecar "${sidecarPath}" is missing the required field "stage".`,
161	    );
162	  }
163	  if (!(VISION_STAGES as readonly string[]).includes(stage)) {
164	    throw new Error(
165	      `[vision-apply] sidecar "${sidecarPath}" stage "${stage}" is not a valid VisionStage. ` +
166	        `Allowed: ${VISION_STAGES.join(', ')}.`,
167	    );
168	  }
169	
170	  // Warn-and-ignore unknown keys.
171	  for (const key of Object.keys(obj)) {
172	    if (!KNOWN_SIDECAR_KEYS.has(key)) {
173	      // eslint-disable-next-line no-console
174	      console.warn(
175	        `[vision-apply] sidecar "${sidecarPath}" has unknown key "${key}" — ignoring.`,
176	      );
177	    }
178	  }
179	
180	  return {
181	    doc,
182	    title,
183	    stage: stage as VisionStage,
184	    codex: readStringField(obj, 'codex'),
185	    visionId: readStringField(obj, 'visionId'),
186	    severity: readStringField(obj, 'severity'),
187	    deadline: readStringField(obj, 'deadline'),
188	    decay: readStringField(obj, 'decay'),
189	    complexity: readStringField(obj, 'complexity'),
190	    resolution: readStringField(obj, 'resolution'),
191	  };
192	}
193	
194	function buildSurveyorPayload(
195	  sidecar: ParsedSidecar,
196	  flags: { severity?: string; deadline?: string; decay?: string },
197	): SurveyorPayload {
198	  const payload: SurveyorPayload = {};
199	  // CLI flags override sidecar values per D10/D11.
200	  const severity = flags.severity ?? sidecar.severity;
201	  const deadline = flags.deadline ?? sidecar.deadline;
202	  const decay = flags.decay ?? sidecar.decay;
203	  // `complexity` is sidecar-only per D9.
204	  const complexity = sidecar.complexity;
205	  if (severity !== undefined) payload.severity = severity;
206	  if (deadline !== undefined) payload.deadline = deadline;
207	  if (decay !== undefined) payload.decay = decay;
208	  if (complexity !== undefined) payload.complexity = complexity;
209	  return payload;
210	}
211	
212	/**
213	 * Atomic-ish sidecar rewrite: write to a temp file in the same
214	 * directory, then rename over the target. Same-directory rename is
215	 * atomic on POSIX filesystems; this avoids the partial-write window
216	 * that would lose the visionId binding on a process crash.
217	 */
218	async function writeSidecarAtomically(
219	  sidecarPath: string,
220	  contents: string,
221	): Promise<void> {
222	  const tmp = `${sidecarPath}.tmp-${process.pid}-${Date.now()}`;
223	  await writeFile(tmp, contents, 'utf8');
224	  await rename(tmp, sidecarPath);
225	}
226	
227	/**
228	 * Round-trip-write the visionId back into the sidecar Document so
229	 * comments and key order survive. Re-emits the document via yaml's
230	 * stringifier, then writes atomically.
231	 */
232	async function persistVisionId(
233	  sidecar: ParsedSidecar,
234	  sidecarPath: string,
235	  visionId: string,
236	): Promise<void> {
237	  sidecar.doc.set('visionId', visionId);
238	  const updated = sidecar.doc.toString();
239	  await writeSidecarAtomically(sidecarPath, updated);
240	}
241	
242	export default tool({
243	  name: 'vision-apply',
244	  description: 'Apply an on-disk vision (snapshot a directory into a vision writ + VisionDoc)',
245	  instructions:
246	    'Reads <guildHome>/vision/<slug>/{vision.md, vision-metadata.yml}, snapshots the ' +
247	    'vision into the cartograph as a vision writ + companion VisionDoc, and writes a ' +
248	    'priority-hint payload into writ.ext[surveyor]. On first apply, the sidecar gains a ' +
249	    'visionId field binding the directory to its writ. On subsequent applies, the bound ' +
250	    'writ is updated in place; missing/cancelled/completed/failed bindings error cleanly. ' +
251	    'CLI flags --severity, --deadline, and --decay override sidecar values for the ' +
252	    'priority-hint payload. The data flow is one-way (file → writ).',
253	  params: {
254	    slug: z
255	      .string()
256	      .regex(
257	        SLUG_REGEX,
258	        'slug must be lowercase letters/digits/hyphens/underscores, must not contain path separators, leading dots, or "..".',
259	      )
260	      .describe('Vision directory slug under <guildHome>/vision/'),
261	    severity: z.string().optional().describe('Override the sidecar severity field for the surveyor priority-hint payload'),
262	    deadline: z.string().optional().describe('Override the sidecar deadline field for the surveyor priority-hint payload'),
263	    decay: z.string().optional().describe('Override the sidecar decay field for the surveyor priority-hint payload'),
264	  },
265	  permission: 'write',
266	  callableBy: ['patron'],
267	  handler: async (params) => {
268	    const { slug } = params;
269	    // Defensive — Zod regex already enforces, but a structurally-typed
270	    // caller could bypass at the type boundary.
271	    if (slug.includes('/') || slug.includes('\\') || slug === '..' || slug.startsWith('.')) {
272	      throw new Error(
273	        `[vision-apply] slug "${slug}" is not a valid directory name (no path separators, no leading dots, no "..").`,
274	      );
275	    }
276	
277	    const home = guild().home;
278	    const visionDir = path.join(home, 'vision', slug);
279	    const visionMdPath = path.join(visionDir, 'vision.md');
280	    const sidecarPath = path.join(visionDir, 'vision-metadata.yml');
281	
282	    // Load both files. Errors are caught and re-thrown with a friendly
283	    // message so the patron sees "missing sidecar" rather than ENOENT.
284	    let bodyText: string;
285	    try {
286	      bodyText = await readFile(visionMdPath, 'utf8');
287	    } catch (err) {
288	      const errno = (err as NodeJS.ErrnoException).code;
289	      if (errno === 'ENOENT') {
290	        throw new Error(
291	          `[vision-apply] vision.md not found at "${visionMdPath}". Create the file or check the slug.`,
292	        );
293	      }
294	      throw err;
295	    }
296	
297	    let sidecarRaw: string;
298	    try {
299	      sidecarRaw = await readFile(sidecarPath, 'utf8');
300	    } catch (err) {
301	      const errno = (err as NodeJS.ErrnoException).code;
302	      if (errno === 'ENOENT') {
303	        throw new Error(
304	          `[vision-apply] vision-metadata.yml not found at "${sidecarPath}". Bootstrap a sidecar with at least "title" and "stage".`,
305	        );
306	      }
307	      throw err;
308	    }
309	
310	    const sidecar = parseSidecar(sidecarRaw, sidecarPath);
311	
312	    // Resolve target phase from sidecar stage.
313	    const targetPhase = STAGE_TO_PHASE[sidecar.stage];
314	
315	    const cartograph = guild().apparatus<CartographApi>('cartograph');
316	    const clerk = guild().apparatus<ClerkApi>('clerk');
317	
318	    const surveyorPayload = buildSurveyorPayload(sidecar, {
319	      ...(params.severity !== undefined ? { severity: params.severity } : {}),
320	      ...(params.deadline !== undefined ? { deadline: params.deadline } : {}),
321	      ...(params.decay !== undefined ? { decay: params.decay } : {}),
322	    });
323	
324	    if (sidecar.visionId === undefined) {
325	      // ── First apply ────────────────────────────────────────────
326	      //
327	      // Reject sunset/cancelled initial stages: cartograph.createVision
328	      // already rejects them, but surface a more specific error here so
329	      // patrons see "first apply" context.
330	      if (sidecar.stage === 'sunset' || sidecar.stage === 'cancelled') {
331	        throw new Error(
332	          `[vision-apply] cannot create a vision with initial stage "${sidecar.stage}" — ` +
333	            `a vision cannot be born retired. Author it as draft or active, then transition.`,
334	        );
335	      }
336	
337	      const doc = await cartograph.createVision({
338	        title: sidecar.title,
339	        body: bodyText,
340	        ...(sidecar.codex !== undefined ? { codex: sidecar.codex } : {}),
341	        phase: targetPhase,
342	        stage: sidecar.stage,
343	      });
344	
345	      // Surveyor slot is always written, even when payload is `{}` —
346	      // its presence marks the writ as processed by apply (D11).
347	      await clerk.setWritExt(doc.id, SURVEYOR_PLUGIN_ID, surveyorPayload);
348	
349	      // Persist the visionId binding. Round-trips the yaml document so
350	      // comments and key order survive (D14); writes atomically (D15).
351	      await persistVisionId(sidecar, sidecarPath, doc.id);
352	
353	      return doc;
354	    }
355	
356	    // ── Nth apply ────────────────────────────────────────────────
357	    //
358	    // Resolve the bound writ. Stale bindings (missing/cancelled/
359	    // completed/failed) error out before any writes — D5.
360	    const boundId = sidecar.visionId;
361	    let writ;
362	    try {
363	      writ = await clerk.show(boundId);
364	    } catch {
365	      throw new Error(
366	        `[vision-apply] sidecar "${sidecarPath}" carries visionId "${boundId}" but no such writ exists. ` +
367	          `The binding is stale — clear the visionId field to re-create, or restore the writ.`,
368	      );
369	    }
370	    if (writ.type !== 'vision') {
371	      throw new Error(
372	        `[vision-apply] writ "${boundId}" is not a vision (type="${writ.type}"). Stale or corrupt binding.`,
373	      );
374	    }
375	    if (TERMINAL_PHASES.has(writ.phase)) {
376	      throw new Error(
377	        `[vision-apply] sidecar "${sidecarPath}" is bound to writ "${boundId}" which is in terminal phase "${writ.phase}". ` +
378	          `Clear the visionId to re-create, or restore the writ to a non-terminal state.`,
379	      );
380	    }
381	
382	    const existingDoc = await cartograph.showVision(boundId);
383	
384	    // Always re-write the body — D12 (no diff-and-skip).
385	    await clerk.edit({ id: boundId, title: sidecar.title, body: bodyText });
386	
387	    // Codex sync: patch the companion doc when the sidecar codex
388	    // differs. This bypasses transitionVision's no-self-transition
389	    // rule (D20).
390	    if ((sidecar.codex ?? undefined) !== (existingDoc.codex ?? undefined)) {
391	      await cartograph.patchVision(boundId, {
392	        ...(sidecar.codex !== undefined ? { codex: sidecar.codex } : { codex: undefined }),
393	      });
394	    }
395	
396	    // Stage/phase sync: only call transitionVision when the target
397	    // phase actually differs from the writ's current phase. Calling it
398	    // when the phase is unchanged would trigger transitionVision's
399	    // self-transition rejection — D20 keeps the no-op at the call
400	    // site and preserves the VISION_CONFIG invariant.
401	    let updatedDoc = existingDoc;
402	    if (writ.phase !== targetPhase) {
403	      updatedDoc = await cartograph.transitionVision(boundId, {
404	        phase: targetPhase,
405	        stage: sidecar.stage,
406	        ...(sidecar.resolution !== undefined ? { resolution: sidecar.resolution } : {}),
407	      });
408	    } else if (existingDoc.stage !== sidecar.stage) {
409	      // Phase unchanged but stage drifted (rare — phase/stage are
410	      // normally locked). Patch the companion doc directly.
411	      updatedDoc = await cartograph.patchVision(boundId, { stage: sidecar.stage });
412	    } else if ((sidecar.codex ?? undefined) !== (existingDoc.codex ?? undefined)) {
413	      // Re-fetch after the codex patch above so the returned doc
414	      // reflects the new codex.
415	      updatedDoc = await cartograph.showVision(boundId);
416	    }
417	
418	    // Refresh the surveyor slot. Always written, even when payload
419	    // is `{}` (D11).
420	    await clerk.setWritExt(boundId, SURVEYOR_PLUGIN_ID, surveyorPayload);
421	
422	    return updatedDoc satisfies VisionDoc;
423	  },
424	});
425	
426	// Re-export the SURVEYOR_PLUGIN_ID for tests; not part of the public
427	// API since the future surveyor-apparatus commission owns the slot.
428	export { SURVEYOR_PLUGIN_ID };
429

