1	/**
2	 * Cartograph apparatus tests.
3	 *
4	 * The fixture wires real stacks + real clerk + the cartograph apparatus
5	 * (production-mirror path) so the writ-type registration-side assertions,
6	 * the typed-API parent validation, the companion-book CRUD round-trip,
7	 * and the lifecycle coupling all run against the production code paths.
8	 *
9	 * Coverage matrix:
10	 *
11	 *   1. Writ-type registration — the three configs land in
12	 *      `clerk.listWritTypes()` with the expected six-state-no-cascade
13	 *      shape.
14	 *   2. Typed-API parent validation — each createX accepts its valid
15	 *      parents and rejects the invalid ones with descriptive errors.
16	 *   3. Companion-book CRUD round-trip — writ id matches doc id, patches
17	 *      preserve unaffected fields, list filters work.
18	 *   4. Lifecycle coupling — `transitionX` updates writ.phase and
19	 *      doc.stage atomically.
20	 */
21	
22	import { describe, it, beforeEach, afterEach } from 'node:test';
23	import assert from 'node:assert/strict';
24	
25	import { setGuild, clearGuild } from '@shardworks/nexus-core';
26	import type {
27	  Guild,
28	  GuildConfig,
29	  LoadedApparatus,
30	  LoadedKit,
31	  StartupContext,
32	} from '@shardworks/nexus-core';
33	
34	import { createStacksApparatus } from '@shardworks/stacks-apparatus';
35	import { MemoryBackend } from '@shardworks/stacks-apparatus/testing';
36	import type { StacksApi } from '@shardworks/stacks-apparatus';
37	
38	import { createClerk } from '@shardworks/clerk-apparatus';
39	import type { ClerkApi, WritDoc } from '@shardworks/clerk-apparatus';
40	
41	import { createCartograph } from './cartograph.ts';
42	import type {
43	  CartographApi,
44	  ChargeDoc,
45	  PieceDoc,
46	  VisionDoc,
47	} from './types.ts';
48	
49	// ── Test harness ─────────────────────────────────────────────────────
50	
51	interface Fixture {
52	  stacks: StacksApi;
53	  clerk: ClerkApi;
54	  cartograph: CartographApi;
55	  memBackend: MemoryBackend;
56	}
57	
58	function buildCtx(): StartupContext {
59	  return {
60	    on(): void {},
61	    kits(): never[] {
62	      return [];
63	    },
64	  };
65	}
66	
67	async function buildFixture(): Promise<Fixture> {
68	  const memBackend = new MemoryBackend();
69	  const stacksPlugin = createStacksApparatus(memBackend);
70	  const clerkPlugin = createClerk();
71	  const cartographPlugin = createCartograph();
72	
73	  const apparatusMap = new Map<string, unknown>();
74	
75	  const fakeGuildConfig: GuildConfig = {
76	    name: 'cartograph-test-guild',
77	    nexus: '0.0.0',
78	    plugins: [],
79	  };
80	
81	  const fakeGuild: Guild = {
82	    home: '/tmp/cartograph-test-guild',
83	    apparatus<T>(name: string): T {
84	      const a = apparatusMap.get(name);
85	      if (!a) throw new Error(`Apparatus "${name}" not installed`);
86	      return a as T;
87	    },
88	
89	    tryApparatus<T>(name: string): T | null {
90	      try { return this.apparatus<T>(name); } catch { return null; }
91	    },
92	    config<T>(_pluginId: string): T {
93	      return {} as T;
94	    },
95	    writeConfig(): void {},
96	    guildConfig(): GuildConfig {
97	      return fakeGuildConfig;
98	    },
99	    kits(): LoadedKit[] {
100	      return [];
101	    },
102	    apparatuses(): LoadedApparatus[] {
103	      return [];
104	    },
105	    failedPlugins() {
106	      return [];
107	    },
108	    startupWarnings(): string[] {
109	      return [];
110	    },
111	  };
112	  setGuild(fakeGuild);
113	
114	  // ── Stacks ────────────────────────────────────────────────────────
115	  stacksPlugin.apparatus.start!(buildCtx());
116	  const stacks = stacksPlugin.apparatus.provides as StacksApi;
117	  apparatusMap.set('stacks', stacks);
118	
119	  // Pre-create the books the Clerk and Cartograph expect. Index shapes
120	  // mirror the supportKit declarations on each apparatus.
121	  memBackend.ensureBook({ ownerId: 'clerk', book: 'writs' }, {
122	    indexes: [
123	      'phase', 'type', 'createdAt', 'parentId',
124	      ['phase', 'type'], ['phase', 'createdAt'], ['parentId', 'phase'],
125	    ],
126	  });
127	  memBackend.ensureBook({ ownerId: 'clerk', book: 'links' }, {
128	    indexes: [
129	      'sourceId', 'targetId', 'label',
130	      ['sourceId', 'label'], ['targetId', 'label'],
131	    ],
132	  });
133	  memBackend.ensureBook({ ownerId: 'cartograph', book: 'visions' }, {
134	    indexes: ['stage', 'codex', 'createdAt'],
135	  });
136	  memBackend.ensureBook({ ownerId: 'cartograph', book: 'charges' }, {
137	    indexes: ['stage', 'codex', 'createdAt'],
138	  });
139	  memBackend.ensureBook({ ownerId: 'cartograph', book: 'pieces' }, {
140	    indexes: ['stage', 'codex', 'createdAt'],
141	  });
142	
143	  // ── Clerk ─────────────────────────────────────────────────────────
144	  await clerkPlugin.apparatus.start!(buildCtx());
145	  const clerk = clerkPlugin.apparatus.provides as ClerkApi;
146	  apparatusMap.set('clerk', clerk);
147	
148	  // ── Cartograph ────────────────────────────────────────────────────
149	  // Per the production wiring, cartograph's start() runs after clerk's
150	  // start() (declared `requires: ['stacks', 'clerk']`). We never fire
151	  // `phase:started`, so the registration window stays open; cartograph's
152	  // three `clerk.registerWritType(...)` calls land here.
153	  await cartographPlugin.apparatus.start!(buildCtx());
154	  const cartograph = cartographPlugin.apparatus.provides as CartographApi;
155	  apparatusMap.set('cartograph', cartograph);
156	
157	  return { stacks, clerk, cartograph, memBackend };
158	}
159	
160	// ── Tests ────────────────────────────────────────────────────────────
161	
162	describe('Cartograph apparatus', () => {
163	  let fix: Fixture;
164	
165	  beforeEach(async () => {
166	    fix = await buildFixture();
167	  });
168	
169	  afterEach(() => {
170	    clearGuild();
171	  });
172	
173	  // ── Writ-type registration ────────────────────────────────────────
174	
175	  describe('writ-type registration', () => {
176	    it('contributes vision, charge, and piece writ types to the Clerk', () => {
177	      const types = fix.clerk.listWritTypes();
178	      const names = types.map((t) => t.name);
179	      assert.ok(names.includes('vision'), 'vision must be registered');
180	      assert.ok(names.includes('charge'), 'charge must be registered');
181	      assert.ok(names.includes('piece'), 'piece must be registered');
182	
183	      for (const name of ['vision', 'charge', 'piece']) {
184	        const t = types.find((entry) => entry.name === name)!;
185	        assert.equal(t.source, 'plugin', `${name} must carry source = "plugin"`);
186	      }
187	    });
188	
189	    it('registers each type with the six-state mandate-clone shape and no cascade', () => {
190	      for (const name of ['vision', 'charge', 'piece']) {
191	        const config = fix.clerk.getWritTypeConfig(name);
192	        assert.ok(config, `${name} config must be retrievable from the registry`);
193	        assert.equal(config!.states.length, 6, `${name} must declare six states`);
194	
195	        const stateNames = config!.states.map((s) => s.name).sort();
196	        assert.deepEqual(
197	          stateNames,
198	          ['cancelled', 'completed', 'failed', 'new', 'open', 'stuck'],
199	          `${name} state catalogue must mirror the mandate clone`,
200	        );
201	
202	        const initial = config!.states.find((s) => s.classification === 'initial');
203	        assert.equal(initial?.name, 'new', `${name} initial state must be "new"`);
204	
205	        const terminals = config!.states
206	          .filter((s) => s.classification === 'terminal')
207	          .map((s) => s.name)
208	          .sort();
209	        assert.deepEqual(
210	          terminals,
211	          ['cancelled', 'completed', 'failed'],
212	          `${name} terminal states must be cancelled/completed/failed`,
213	        );
214	
215	        // No cascade — patron-walkthrough semantics are coordinated
216	        // upstream of the registry.
217	        assert.equal(
218	          config!.childrenBehavior,
219	          undefined,
220	          `${name} must NOT declare childrenBehavior`,
221	        );
222	      }
223	    });
224	  });
225	
226	  // ── createVision: parent invariants ────────────────────────────────
227	
228	  describe('createVision', () => {
229	    it('creates a top-level vision with no parent', async () => {
230	      const vision = await fix.cartograph.createVision({
231	        title: 'Land the ladder',
232	        body: 'long-form vision text',
233	        codex: 'main',
234	      });
235	
236	      assert.ok(vision.id.startsWith('w-'), 'vision id must follow writ id convention');
237	      assert.equal(vision.stage, 'draft');
238	      assert.equal(vision.codex, 'main');
239	      assert.ok(vision.createdAt);
240	      assert.ok(vision.updatedAt);
241	
242	      // The companion writ row is also present and well-formed.
243	      const writ = await fix.clerk.show(vision.id);
244	      assert.equal(writ.type, 'vision');
245	      assert.equal(writ.phase, 'new');
246	      assert.equal(writ.title, 'Land the ladder');
247	      assert.equal(writ.body, 'long-form vision text');
248	      assert.equal(writ.codex, 'main');
249	      assert.equal(writ.parentId, undefined);
250	    });
251	
252	    // ── Initial phase + stage (vision-apply substrate) ──────────────
253	
254	    it('accepts an explicit (phase=open, stage=active) pair on first creation', async () => {
255	      const vision = await fix.cartograph.createVision({
256	        title: 'Active from birth',
257	        body: 'B',
258	        phase: 'open',
259	        stage: 'active',
260	      });
261	      assert.equal(vision.stage, 'active');
262	      const writ = await fix.clerk.show(vision.id);
263	      assert.equal(writ.phase, 'open');
264	    });
265	
266	    it('accepts stage=active without an explicit phase (phase auto-resolves to open)', async () => {
267	      const vision = await fix.cartograph.createVision({
268	        title: 'Active stage only',
269	        body: 'B',
270	        stage: 'active',
271	      });
272	      assert.equal(vision.stage, 'active');
273	      const writ = await fix.clerk.show(vision.id);
274	      assert.equal(writ.phase, 'open');
275	    });
276	
277	    it('accepts phase=open without an explicit stage (stage auto-resolves to active)', async () => {
278	      // Phase-only callers fall through to the default stage `draft`,
279	      // which then mismatches with the supplied phase. The resolution
280	      // path uses the stage as the source of truth, so the explicit
281	      // phase has to agree with the default stage's expected phase.
282	      // For now this means a phase-only call with phase=open is rejected
283	      // (default stage `draft` ↔ phase `new`); patrons must supply both
284	      // when overriding from the default. Verify the rejection is loud.
285	      await assert.rejects(
286	        () =>
287	          fix.cartograph.createVision({
288	            title: 'Phase-only override',
289	            body: 'B',
290	            phase: 'open',
291	          }),
292	        /does not pair with stage/,
293	      );
294	    });
295	
296	    it('rejects sunset as an initial stage', async () => {
297	      await assert.rejects(
298	        () =>
299	          fix.cartograph.createVision({
300	            title: 'Born retired',
301	            body: 'B',
302	            stage: 'sunset',
303	          }),
304	        (err: Error) => {
305	          assert.match(err.message, /cannot be born retired/);
306	          return true;
307	        },
308	      );
309	    });
310	
311	    it('rejects cancelled as an initial stage', async () => {
312	      await assert.rejects(
313	        () =>
314	          fix.cartograph.createVision({
315	            title: 'Born cancelled',
316	            body: 'B',
317	            stage: 'cancelled',
318	          }),
319	        (err: Error) => {
320	          assert.match(err.message, /cannot be born retired/);
321	          return true;
322	        },
323	      );
324	    });
325	
326	    it('rejects a phase/stage mismatch with a clear error', async () => {
327	      await assert.rejects(
328	        () =>
329	          fix.cartograph.createVision({
330	            title: 'Mismatched',
331	            body: 'B',
332	            phase: 'new',
333	            stage: 'active',
334	          }),
335	        (err: Error) => {
336	          assert.match(err.message, /does not pair/);
337	          return true;
338	        },
339	      );
340	    });
341	
342	    it('produces exactly one CDC event on the cartograph visions book per creation', async () => {
343	      let createCount = 0;
344	      let updateCount = 0;
345	      fix.stacks.watch<VisionDoc>('cartograph', 'visions', (event) => {
346	        if (event.type === 'create') createCount += 1;
347	        if (event.type === 'update') updateCount += 1;
348	      });
349	
350	      // Default-state creation.
351	      await fix.cartograph.createVision({ title: 'V1', body: 'B' });
352	      assert.equal(createCount, 1, 'first createVision emits one create event');
353	      assert.equal(updateCount, 0, 'no update events on initial creation');
354	
355	      // Bootstrap directly into active state — still exactly one event.
356	      await fix.cartograph.createVision({
357	        title: 'V2',
358	        body: 'B',
359	        phase: 'open',
360	        stage: 'active',
361	      });
362	      assert.equal(createCount, 2, 'second createVision emits one more create event');
363	      assert.equal(updateCount, 0, 'still no update events — coalescing collapses tx writes');
364	    });
365	
366	    // Parent validation — visions have no parent.
367	    it('rejects a non-empty parentId with a descriptive error', async () => {
368	      // Create a parent vision so the would-be parent exists.
369	      const parent = await fix.cartograph.createVision({
370	        title: 'Parent',
371	        body: 'P',
372	      });
373	
374	      await assert.rejects(
375	        () =>
376	          (fix.cartograph as unknown as {
377	            createVision: (req: {
378	              title: string;
379	              body: string;
380	              parentId?: string;
381	            }) => Promise<VisionDoc>;
382	          }).createVision({
383	            title: 'Child vision',
384	            body: 'Should fail',
385	            parentId: parent.id,
386	          }),
387	        (err: Error) => {
388	          assert.match(err.message, /vision/i);
389	          assert.match(err.message, /parent/i);
390	          return true;
391	        },
392	      );
393	    });
394	  });
395	
396	  // ── createCharge: parent invariants ────────────────────────────────
397	
398	  describe('createCharge', () => {
399	    it('creates a charge under a vision and inherits the codex', async () => {
400	      const vision = await fix.cartograph.createVision({
401	        title: 'V',
402	        body: 'B',
403	        codex: 'main',
404	      });
405	
406	      const charge = await fix.cartograph.createCharge({
407	        parentId: vision.id,
408	        title: 'C',
409	        body: 'B',
410	      });
411	
412	      assert.equal(charge.codex, 'main', 'charge inherits parent vision codex');
413	      const chargeWrit = await fix.clerk.show(charge.id);
414	      assert.equal(chargeWrit.type, 'charge');
415	      assert.equal(chargeWrit.parentId, vision.id);
416	      assert.equal(chargeWrit.codex, 'main');
417	    });
418	
419	    it('rejects when parent type is not vision', async () => {
420	      // A mandate-typed parent is not a valid charge parent.
421	      const mandate = await fix.clerk.post({
422	        type: 'mandate',
423	        title: 'wrong parent',
424	        body: 'B',
425	      });
426	
427	      await assert.rejects(
428	        () =>
429	          fix.cartograph.createCharge({
430	            parentId: mandate.id,
431	            title: 'illegal charge',
432	            body: 'B',
433	          }),
434	        (err: Error) => {
435	          assert.match(err.message, /charge/i);
436	          assert.match(err.message, /vision/i);
437	          assert.match(err.message, /mandate/);
438	          return true;
439	        },
440	      );
441	    });
442	
443	    it('rejects when parentId references a non-existent writ', async () => {
444	      await assert.rejects(
445	        () =>
446	          fix.cartograph.createCharge({
447	            parentId: 'w-nonexistent',
448	            title: 'orphan',
449	            body: 'B',
450	          }),
451	        (err: Error) => {
452	          assert.match(err.message, /not found/);
453	          return true;
454	        },
455	      );
456	    });
457	
458	    it('rejects when parent vision is in a terminal state', async () => {
459	      const vision = await fix.cartograph.createVision({
