202	export function createClerk(): Plugin {
203	  let stacks: StacksApi;
204	  let writs: Book<WritDoc>;
205	  let links: Book<WritLinkDoc>;
206	
207	  /** Internal metadata stored per registered link kind. */
208	  interface KindMeta {
209	    ownerPlugin: string;
210	    description: string;
211	  }
212	
213	  /** Registry of kit-contributed link kinds, keyed by kind id. */
214	  let linkKindRegistry: Map<string, KindMeta> = new Map();
215	
216	  // ── Writ-type registry ──────────────────────────────────────────────
217	  //
218	  // The runtime registry of plugin-registered writ-type state machines.
219	  // `registerWritType` is the only path for a plugin to contribute a writ
220	  // type; the registry is sealed at the framework's global `phase:started`
221	  // signal so registration is a startup-window-only operation. `sealed`
222	  // flips to `true` once the window closes — further calls throw.
223	
224	  /** Internal entry shape — pairs the config with a coarse source tag. */
225	  interface WritTypeRegistryEntry {
226	    config: WritTypeConfig;
227	    /**
228	     * Origin of this registered type. `'builtin'` is reserved for mandate,
229	     * which the Clerk plugin registers from its own `start()`; every other
230	     * registered type carries `'plugin'`. The Clerk does not currently
231	     * track the calling plugin's id — `registerWritType` is invoked from
232	     * that plugin's `start()` and there is no implicit hand-off of the
233	     * caller's identity into the API.
234	     */
235	    source: 'builtin' | 'plugin';
236	  }
237	
238	  /** Sealed registry of plugin-registered writ-type state machines. */
239	  const writTypeRegistry: Map<string, WritTypeRegistryEntry> = new Map();
240	
241	  /** Whether the registry has sealed. Flipped by `phase:started`. */
242	  let writTypeRegistrySealed = false;
243	
244	  /**
245	   * Internal registration helper used by both the public `registerWritType`
246	   * and the Clerk's own start()-time mandate registration. Centralises the
247	   * validate/seal/duplicate checks so the public API stays a thin wrapper
248	   * that defaults source to `'plugin'`.
249	   */
250	  function registerWritTypeInternal(
251	    config: WritTypeConfig,
252	    source: 'builtin' | 'plugin',
253	  ): void {
254	    // Validator errors propagate verbatim — their `[clerk]
255	    // writTypeConfig.<path>: <problem>` shape already names the offending
256	    // field precisely; wrapping would hide the path. Registration-specific
257	    // failures (sealed registry, duplicate name) are wrapped with a
258	    // `[clerk] registerWritType:` prefix so callers can distinguish the
259	    // two failure modes.
260	    validateWritTypeConfig(config);
261	
262	    if (writTypeRegistrySealed) {
263	      throw new Error(
264	        `[clerk] registerWritType: cannot register writ type "${config.name}" — the startup registration window has closed. Plugins must call registerWritType from their apparatus's start() before the framework fires phase:started.`,
265	      );
266	    }
267	
268	    const existing = writTypeRegistry.get(config.name);
269	    if (existing) {
270	      throw new Error(
271	        `[clerk] registerWritType: duplicate writ type "${config.name}" — already registered. Two plugins cannot contribute the same writ type name.`,
272	      );
273	    }
274	
275	    writTypeRegistry.set(config.name, { config, source });
276	  }
277	
278	  /**
279	   * Grammar for kind-id suffixes after the `{pluginId}.` prefix.
280	   *
281	   * Kebab-case only: lowercase letters, digits, and hyphens. Must not start
282	   * or end with a hyphen and must have at least one character.
283	   */
284	  const KIND_SUFFIX_RE = /^[a-z0-9]+(?:-[a-z0-9]+)*$/;
285	
286	  // ── Helpers ──────────────────────────────────────────────────────
287	
288	  function resolveClerkConfig(): ClerkConfig {
289	    return guild().guildConfig().clerk ?? {};
290	  }
291	
292	  function resolveDefaultType(): string {
293	    const config = resolveClerkConfig();
294	    return config.defaultType ?? MANDATE_TYPE_NAME;
295	  }
296	
297	  /**
298	   * Return the classification of a writ's current state, looked up from its
299	   * type's registered `WritTypeConfig`. Throws with a fail-loud message
300	   * when the writ's type is not registered, or when its stored state is
301	   * not declared in that type's config (D6).
302	   */
303	  function classifyWritState(writ: WritDoc): 'initial' | 'active' | 'terminal' {
304	    const entry = writTypeRegistry.get(writ.type);
305	    if (!entry) {
306	      throw new Error(
307	        `[clerk] writ "${writ.id}" carries type "${writ.type}" which is not registered; registered types are ${
308	          writTypeRegistry.size === 0
309	            ? '(none)'
310	            : [...writTypeRegistry.keys()].map((n) => `"${n}"`).join(', ')
311	        }.`,
312	      );
313	    }
314	    const state = entry.config.states.find((s) => s.name === writ.phase);
315	    if (!state) {
316	      const legal = entry.config.states.map((s) => `"${s.name}"`).join(', ');
317	      throw new Error(
318	        `[clerk] writ "${writ.id}" carries state "${writ.phase}" which is not declared in type "${writ.type}" config; legal states are ${legal}.`,
319	      );
320	    }
321	    return state.classification;
322	  }
323	
324	  /**
325	   * Return the state classified `initial` for a registered writ type, or
326	   * throw when the type is not registered. The validator guarantees
327	   * exactly-one `initial` state per registered config, so the find() is
328	   * total.
329	   */
330	  function resolveInitialState(typeName: string): string {
331	    const entry = writTypeRegistry.get(typeName);
332	    if (!entry) {
333	      throw new Error(
334	        `Unknown writ type "${typeName}". Registered types: ${
335	          writTypeRegistry.size === 0
336	            ? '(none)'
337	            : [...writTypeRegistry.keys()].join(', ')
338	        }.`,
339	      );
340	    }
341	    const initial = entry.config.states.find((s) => s.classification === 'initial');
342	    if (!initial) {
343	      // validateWritTypeConfig() enforces exactly-one `initial` state, so this
344	      // branch is only reachable if the validator's invariants regressed.
345	      throw new Error(
346	        `[clerk] writ type "${typeName}" has no initial state; the type config is malformed.`,
347	      );
348	    }
349	    return initial.name;
350	  }
351	
352	  /**
353	   * Resolve the effective `type` filter according to T5/D7's implicit
354	   * mandate-scope rule: when `phase` is supplied without an explicit
355	   * `type`, the WHERE clause adds `type = 'mandate'` automatically so a
356	   * non-mandate writ that happens to declare an `open` state cannot
357	   * match `--phase open` unscoped to its type. The operator can override
358	   * by passing both `--type X --phase Y` together.
359	   */
360	  function resolveTypeFilter(
361	    filters?: { phase?: unknown; type?: string | string[] },
362	  ): string[] | undefined {
363	    if (filters?.type !== undefined) {
364	      return Array.isArray(filters.type) ? filters.type : [filters.type];
365	    }
366	    if (filters?.phase !== undefined) {
367	      return [MANDATE_TYPE_NAME];
368	    }
369	    return undefined;
370	  }
371	
372	  /**
373	   * Map a (possibly-array) classification filter to the union of state
374	   * names that match it across the named types. Used to translate the
375	   * type-agnostic `classification` filter into a SQL-level `phase` IN
376	   * predicate. When no concrete types narrow the search, the union spans
377	   * every registered type's state catalogue.
378	   */
379	  function resolveClassificationStates(
380	    classification: WritTypeStateClassification | WritTypeStateClassification[],
381	    typeFilter?: string[],
382	  ): string[] {
383	    const requested = Array.isArray(classification) ? classification : [classification];
384	    const requestedSet = new Set(requested);
385	    const types = typeFilter && typeFilter.length > 0
386	      ? typeFilter
387	      : [...writTypeRegistry.keys()];
388	    const matching = new Set<string>();
389	    for (const typeName of types) {
390	      const entry = writTypeRegistry.get(typeName);
391	      if (!entry) continue;
392	      for (const state of entry.config.states) {
393	        if (requestedSet.has(state.classification)) {
394	          matching.add(state.name);
395	        }
396	      }
397	    }
398	    return [...matching];
399	  }
400	
401	  function buildWhereClause(filters?: WritFilters): WhereClause | undefined {
402	    const conditions: WhereClause = [];
403	
404	    // Resolve `type` first because the classification translator may
405	    // need it. Apply T5/D7's implicit mandate-scope rule: when `phase` is
406	    // supplied without an explicit `type`, scope to mandate.
407	    const effectiveType = resolveTypeFilter(filters);
408	
409	    if (filters?.phase) {
410	      const phases = Array.isArray(filters.phase) ? filters.phase : [filters.phase];
411	      if (phases.length === 1) {
412	        conditions.push(['phase', '=', phases[0]!]);
413	      } else if (phases.length > 1) {
414	        conditions.push(['phase', 'IN', phases]);
415	      }
416	    }
417	
418	    if (filters?.classification !== undefined) {
419	      const stateNames = resolveClassificationStates(
420	        filters.classification,
421	        effectiveType,
422	      );
423	      if (stateNames.length === 0) {
424	        // Closed-world: no registered state matches the requested
425	        // classification. Emit a sentinel predicate that never matches
426	        // (compares the indexed `phase` column to a string that is never
427	        // a valid state name). This is rare in practice — every
428	        // registered type declares at least one initial and one
429	        // terminal state — but the branch keeps the result stable.
430	        conditions.push(['phase', '=', '__no_match__']);
431	      } else if (stateNames.length === 1) {
432	        conditions.push(['phase', '=', stateNames[0]!]);
433	      } else {
434	        conditions.push(['phase', 'IN', stateNames]);
435	      }
436	    }
437	
438	    if (effectiveType !== undefined) {
439	      if (effectiveType.length === 1) {
440	        conditions.push(['type', '=', effectiveType[0]!]);
441	      } else if (effectiveType.length > 1) {
442	        conditions.push(['type', 'IN', effectiveType]);
443	      }
444	    }
445	
446	    if (filters?.parentId) {
447	      conditions.push(['parentId', '=', filters.parentId]);
448	    }
449	    return conditions.length > 0 ? conditions : undefined;
450	  }
451	
452	  function registerKitLinkKinds(kitEntry: { pluginId: string; value: unknown }): void {
453	    const pluginId = kitEntry.pluginId;
454	    const raw = kitEntry.value;
455	    if (!Array.isArray(raw)) {
456	      throw new Error(
457	        `[clerk] Kit "${pluginId}" linkKinds: expected an array, got ${typeof raw}.`,
458	      );
459	    }
460	
461	    for (const entry of raw) {
462	      if (typeof entry !== 'object' || entry === null) {
463	        throw new Error(
464	          `[clerk] Kit "${pluginId}" linkKinds: entry is not an object (got ${entry === null ? 'null' : typeof entry}).`,
465	        );
466	      }
467	      const rec = entry as Record<string, unknown>;
468	      const id = rec.id;
469	      const description = rec.description;
470	
471	      if (typeof id !== 'string' || id.length === 0) {
472	        throw new Error(
473	          `[clerk] Kit "${pluginId}" linkKinds: entry is missing a non-empty string "id" field.`,
474	        );
475	      }
476	      if (typeof description !== 'string' || description.length === 0) {
477	        throw new Error(
478	          `[clerk] Kit "${pluginId}" linkKinds: entry "${id}" is missing a non-empty string "description" field.`,
479	        );
480	      }
481	
482	      // ── Clerk-only carve-out for unprefixed kind ids ──
483	      //
484	      // The Clerk plugin owns the writ link substrate, so it is granted
485	      // primacy over the unprefixed namespace within that substrate. Only
486	      // contributions from `pluginId === CLERK_PLUGIN_ID` may use a bare
487	      // kebab id (e.g. `depends-on`); every other plugin must continue to
488	      // use the prefixed `{pluginId}.{kebab-suffix}` form.
489	      //
490	      // The carve-out admits exactly two forms when the contributor is
491	      // Clerk:
492	      //   - `X` (unprefixed kebab id), or
493	      //   - `clerk.X` (prefixed kebab id).
494	      // A Clerk contribution containing a `.` whose left side is not
495	      // `'clerk'` is malformed and falls through to the standard
496	      // prefix-equals-pluginId rejection below.
497	      //
498	      // Only the dot-required and prefix-equals-pluginId checks are
499	      // short-circuited for the Clerk-unprefixed path; kebab grammar and
500	      // registry-wide duplicate detection still apply.
501	      if (pluginId === CLERK_PLUGIN_ID && id.indexOf('.') === -1) {
502	        if (!KIND_SUFFIX_RE.test(id)) {
503	          throw new Error(
504	            `[clerk] Kit "${pluginId}" linkKinds: entry "${id}" must be kebab-case (lowercase letters, digits, and hyphens, not starting or ending with "-").`,
505	          );
506	        }
507	
508	        if (linkKindRegistry.has(id)) {
509	          const existing = linkKindRegistry.get(id)!;
510	          throw new Error(
511	            `[clerk] Kit "${pluginId}" linkKinds: duplicate kind id "${id}" — already registered by kit "${existing.ownerPlugin}".`,
512	          );
513	        }
514	
515	        linkKindRegistry.set(id, {
516	          ownerPlugin: pluginId,
517	          description,
518	        });
519	        continue;
520	      }
521	
522	      const dotIdx = id.indexOf('.');
523	      if (dotIdx <= 0 || dotIdx === id.length - 1) {
524	        throw new Error(
525	          `[clerk] Kit "${pluginId}" linkKinds: entry "${id}" must be of the form "{pluginId}.{kebab-suffix}".`,
526	        );
527	      }
528	      const prefix = id.slice(0, dotIdx);
529	      const suffix = id.slice(dotIdx + 1);
530	
531	      if (prefix !== pluginId) {
532	        throw new Error(
533	          `[clerk] Kit "${pluginId}" linkKinds: entry "${id}" has prefix "${prefix}" but must match the contributing plugin id "${pluginId}".`,
534	        );
535	      }
536	
537	      if (!KIND_SUFFIX_RE.test(suffix)) {
538	        throw new Error(
539	          `[clerk] Kit "${pluginId}" linkKinds: entry "${id}" suffix "${suffix}" must be kebab-case (lowercase letters, digits, and hyphens, not starting or ending with "-").`,
540	        );
541	      }
542	
543	      if (linkKindRegistry.has(id)) {
544	        const existing = linkKindRegistry.get(id)!;
545	        throw new Error(
546	          `[clerk] Kit "${pluginId}" linkKinds: duplicate kind id "${id}" — already registered by kit "${existing.ownerPlugin}".`,
547	        );
548	      }
549	
550	      linkKindRegistry.set(id, {
551	        ownerPlugin: pluginId,
552	        description,
553	      });
554	    }
555	  }
