557	  // ── Presentation helpers ──────────────────────────────────────────
558	
559	  /**
560	   * Project a stored `WritDoc` onto its presentation shape — same fields,
561	   * plus the derived `classification` and `allowedTransitions`. Reads the
562	   * type-config registry through the closure; tolerant of unregistered
563	   * types and undeclared states (presentation-side fallback to
564	   * `'unknown'` per `derivePresentation`'s contract).
565	   */
566	  function presentWrit(writ: WritDoc): WritWithPresentation {
567	    const projection = derivePresentation(
568	      writ,
569	      (name) => writTypeRegistry.get(name)?.config,
570	    );
571	    return {
572	      ...writ,
573	      classification: projection.classification,
574	      allowedTransitions: projection.allowedTransitions,
575	    };
576	  }
577	
578	  // ── Tree walker ──────────────────────────────────────────────────
579	
580	  /**
581	   * Build a single `WritTree` rooted at `writId`. Returns null when the node
582	   * (or its subtree, after filters) is fully pruned. Mirrors ratchet's
583	   * `buildTree()`.
584	   *
585	   * Children are queried via the `parentId` index and recursed in
586	   * `createdAt asc` order so the visual order is stable across
587	   * sorts/filters at the page layer.
588	   */
589	  async function buildTree(
590	    writId: string,
591	    options?: {
592	      phaseSet?: Set<WritPhase>;
593	      typeSet?: Set<string>;
594	      classificationSet?: Set<WritTypeStateClassification>;
595	      depth?: number;
596	      currentDepth?: number;
597	    },
598	  ): Promise<WritTree | null> {
599	    const writ = await writs.get(writId);
600	    if (!writ) return null;
601	
602	    const phaseSet = options?.phaseSet;
603	    const typeSet = options?.typeSet;
604	    const classificationSet = options?.classificationSet;
605	    const maxDepth = options?.depth;
606	    const currentDepth = options?.currentDepth ?? 0;
607	
608	    // Prune: drop the node and its subtree when it fails any filter.
609	    if (phaseSet && !phaseSet.has(writ.phase as WritPhase)) return null;
610	    if (typeSet && !typeSet.has(writ.type)) return null;
611	    if (classificationSet) {
612	      // Translate the writ's stored phase to its classification through the
613	      // registry. Unknown-classification writs (unregistered type / undeclared
614	      // state) never satisfy the predicate — they prune.
615	      const projection = derivePresentation(writ, (name) =>
616	        writTypeRegistry.get(name)?.config,
617	      );
618	      if (
