767	    async countActive(): Promise<number> {
768	      // Walk the registry per call (D13) — no caching, no
769	      // post-seal memo. Drain runs at most once per terminal
770	      // transition; the walk is microseconds.
771	      //
772	      // Compose one OR-branch per registered type, each shaped as
773	      // `[type = T, phase IN [...activeStatesOf(T)]]`. The composite
774	      // `[type, phase]` index on the writs book serves the lookup.
775	      // Types with no `active` state contribute no branch; an empty
776	      // `or: []` list collapses to `count() === 0` (D2).
777	      const branches: WhereClause[] = [];
778	      for (const [typeName, entry] of writTypeRegistry.entries()) {
779	        const activeStates = entry.config.states
780	          .filter((s) => s.classification === 'active')
781	          .map((s) => s.name);
782	        if (activeStates.length === 0) continue;
783	        if (activeStates.length === 1) {
784	          branches.push([
785	            ['type', '=', typeName],
786	            ['phase', '=', activeStates[0]!],
787	          ]);
788	        } else {
789	          branches.push([
790	            ['type', '=', typeName],
791	            ['phase', 'IN', activeStates],
792	          ]);
793	        }
794	      }
795	      if (branches.length === 0) return 0;
796	      return writs.count({ or: branches });
