799	    async tree(params?: WritTreeParams): Promise<WritTree[]> {
800	      const phaseSet = params?.phase
801	        ? new Set(Array.isArray(params.phase) ? params.phase : [params.phase])
802	        : undefined;
803	      // Apply T5/D7's implicit mandate-scope at the tree layer too: when
804	      // `phase` is supplied without `type`, scope the type filter to
805	      // mandate so a non-mandate writ sharing a same-named state cannot
806	      // leak into the result.
807	      let typeSet: Set<string> | undefined = params?.type
808	        ? new Set(Array.isArray(params.type) ? params.type : [params.type])
809	        : undefined;
810	      if (typeSet === undefined && phaseSet !== undefined) {
811	        typeSet = new Set([MANDATE_TYPE_NAME]);
812	      }
813	      const classificationSet = params?.classification
814	        ? new Set(
815	            Array.isArray(params.classification)
816	              ? params.classification
817	              : [params.classification],
818	          )
819	        : undefined;
820	      const opts = { phaseSet, typeSet, classificationSet, depth: params?.depth };
821	
822	      // Subtree mode — single root, root-slice params ignored.
823	      if (params?.rootId) {
824	        const tree = await buildTree(params.rootId, opts);
825	        return tree ? [tree] : [];
826	      }
827	
828	      // Forest mode — find all roots (no parentId), then page across them.
829	      // We can't query parentId = undefined reliably across backends (some
830	      // store missing fields differently), so fetch and filter.
831	      const all = await writs.find({
832	        orderBy: ['createdAt', 'desc'],
833	        limit: 100000,
834	      });
835	      const rootDocs = all.filter((w) => !w.parentId);
836	
837	      const rootOffset = params?.rootOffset ?? 0;
838	      const rootLimit = params?.rootLimit;
839	      const slicedRoots = rootLimit !== undefined
840	        ? rootDocs.slice(rootOffset, rootOffset + rootLimit)
841	        : rootDocs.slice(rootOffset);
842	
843	      const forest: WritTree[] = [];
844	      for (const root of slicedRoots) {
845	        const tree = await buildTree(root.id, opts);
846	        if (tree) forest.push(tree);
847	      }
848	      return forest;
849	    },
