851	    async countDescendantsByPhase(writId: string): Promise<Record<WritPhase, number>> {
852	      // Validate the root exists up front so callers get a clear error rather
853	      // than a silent zero-count result for an invalid id.
854	      const root = await writs.get(writId);
855	      if (!root) {
856	        throw new Error(`Writ "${writId}" not found.`);
857	      }
858	
859	      const counts: Record<WritPhase, number> = {} as Record<WritPhase, number>;
860	
861	      // Per-level recursive walk, mirroring ratchet's buildTree / collectDescendantIds.
862	      // Uses the existing `[parentId, phase]` composite index — no extra index needed.
863	      // No depth cap, no cycle guard; we trust the parentId-immutability invariant.
864	      async function walk(parentId: string): Promise<void> {
865	        const children = await writs.find({ where: [['parentId', '=', parentId]] });
866	        for (const child of children) {
867	          const phase = child.phase as WritPhase;
868	          counts[phase] = (counts[phase] ?? 0) + 1;
869	          await walk(child.id);
870	        }
871	      }
872	
873	      await walk(writId);
874	      return counts;
