1216	  // ── writ-types tool ──────────────────────────────────────────────
1217	
1218	  const writTypesTool = tool({
1219	    name: 'writ-types',
1220	    description: 'List available writ types for this guild',
1221	    instructions:
1222	      'Returns the writ types registered with the Clerk via ' +
1223	      '`registerWritType`, including the Clerk\'s own `mandate`. Each entry ' +
1224	      'reports the type name, source (`builtin` or `plugin`), and whether ' +
1225	      'it is the default type.',
1226	    params: {},
1227	    permission: 'read',
1228	    handler: async () => api.listWritTypes(),
1229	  });
1230	
1231	  // ── Apparatus ────────────────────────────────────────────────────
1232	
1233	  return {
1234	    apparatus: {
1235	      requires: ['stacks'],
1236	      recommends: ['oculus', 'codexes'],
1237	      consumes: ['linkKinds'],
1238	
1239	      supportKit: {
1240	        books: {
1241	          writs: {
1242	            indexes: ['phase', 'type', 'createdAt', 'parentId', ['phase', 'type'], ['phase', 'createdAt'], ['parentId', 'phase']],
1243	          },
1244	          links: {
1245	            indexes: ['sourceId', 'targetId', 'label', ['sourceId', 'label'], ['targetId', 'label']],
1246	          },
1247	        },
1248	        linkKinds: [
1249	          {
1250	            id: 'depends-on',
1251	            description:
1252	              'The source writ is a precedence-successor of the target: source cannot be dispatched until the target reaches a terminal state. Consumers define their own policy for what happens on each terminal state.',
1253	          },
1254	        ],
1255	        tools: [
1256	          commissionPost,
1257	          stepAdd,
1258	          writShow,
1259	          writList,
1260	          writTree,
1261	          writEdit,
1262	          writComplete,
1263	          writFail,
1264	          writCancel,
1265	          writPublish,
1266	          writLink,
1267	          writUnlink,
1268	          writLinkKinds,
1269	          writLinkKindsShow,
1270	          writTypesTool,
1271	        ],
1272	        pages: [
1273	          { id: 'writs', title: 'Writs', dir: 'pages/writs' },
1274	        ],
1275	      },
1276	
1277	      provides: api,
1278	
1279	      async start(ctx: StartupContext): Promise<void> {
1280	        const g = guild();
1281	        stacks = g.apparatus<StacksApi>('stacks');
1282	        writs = stacks.book<WritDoc>('clerk', 'writs');
1283	        links = stacks.book<WritLinkDoc>('clerk', 'links');
1284	
1285	        // ── Children-behavior cascade engine ───────────────────────────
1286	        //
1287	        // Phase 1 watch on the writs book: when any writ transitions to a
1288	        // terminal state, evaluate the parent's `WritTypeConfig.children
1289	        // Behavior` block and apply the configured action via
1290	        // `api.transition`. The engine is generic in writ type — types
1291	        // that omit the block are silent no-ops; mandate is the only
1292	        // built-in opt-in today. failOnError: true means cascade writes
1293	        // join the triggering transaction, mirroring Spider's writ↔rig
1294	        // cascade. Grandparent lift is natural recursion via Stacks'
1295	        // re-fire on the parent's own update event.
1296	        const childrenBehaviorHandler = createChildrenBehaviorEngine({
1297	          writs,
1298	          getWritTypeConfig: (name: string) => writTypeRegistry.get(name)?.config,
1299	          isTerminal: (writ: WritDoc) => api.isTerminal(writ),
1300	          transition: (id: string, to, fields) => api.transition(id, to, fields),
1301	          setWritStatus: (writId: string, pluginId: string, value: unknown) =>
1302	            api.setWritStatus(writId, pluginId, value),
1303	        });
1304	        stacks.watch<WritDoc>('clerk', 'writs', childrenBehaviorHandler, {
1305	          failOnError: true,
1306	        });
1307	
1308	        // Seal the writ-type registration window on the framework's global
1309	        // `phase:started` signal — that moment fires once, after every
1310	        // apparatus's `start()` has completed, which mirrors how stacks seals
1311	        // its CDC watcher registry. Per-apparatus `apparatus:started` events
1312	        // fire too early to catch every contributor, and we want plugins to
1313	        // be able to register types from their own `start()` regardless of
1314	        // dependency ordering.
1315	        //
1316	        // The same handler validates `clerk.defaultType` against the now-
1317	        // sealed registry: by the time `phase:started` fires, every
1318	        // plugin's `start()` has run, so any plugin-contributed type the
1319	        // operator named as default has had its chance to register. A
1320	        // missing default type is a startup error.
1321	        ctx.on('phase:started', () => {
1322	          writTypeRegistrySealed = true;
1323	
1324	          const clerkConfig = resolveClerkConfig();
1325	          if (
1326	            clerkConfig.defaultType !== undefined &&
1327	            !writTypeRegistry.has(clerkConfig.defaultType)
1328	          ) {
1329	            throw new Error(
1330	              `[clerk] guild config: defaultType "${clerkConfig.defaultType}" is not a registered writ type. Registered types: ${
1331	                writTypeRegistry.size === 0
1332	                  ? '(none)'
1333	                  : [...writTypeRegistry.keys()].join(', ')
1334	              }.`,
1335	            );
1336	          }
1337	        });
1338	
1339	        // Register the built-in `mandate` writ type with the new registry.
1340	        // `post()` and `transition()` route through the registry; mandate is
1341	        // the one type the Clerk plugin contributes for itself.
1342	        registerWritTypeInternal(MANDATE_CONFIG, 'builtin');
1343	
1344	        // Scan all kit-contributed link kinds via the Wire-phase snapshot.
1345	        // Malformed entries hard-fail the start() call — a reserved kind id
1346	        // that silently disappears would be worse than a startup failure,
1347	        // because downstream consumers key on it.
1348	        linkKindRegistry = new Map();
1349	        for (const entry of ctx.kits('linkKinds')) {
1350	          registerKitLinkKinds(entry);
1351	        }
1352	
1353	        // ── One-shot migration: rename `status` → `phase`, subsume legacy values ──
1354	        // Safe to run inside start(): stacks only seals the CDC registry
1355	        // at phase:started (after every apparatus has started), so these
1356	        // writes don't lock out downstream apparatuses that register
1357	        // watchers in their own start().
1358	        //
1359	        // Every pre-rename row carries its lifecycle value in `status`.
1360	        // Post-rename rows carry `phase` instead, and `status` becomes the
1361	        // plugin-owned observation slot. We iterate every row, compute a
1362	        // clean post-rename document, and `put()` it back — `patch()` can't
1363	        // remove a field, so the full rewrite is required.
1364	        //
1365	        // Legacy lifecycle values (`ready`, `active`, `waiting`) are
1366	        // collapsed into `open` along the way (this subsumes the older
1367	        // `legacyStatuses` migration). Any unrecognized value aborts
1368	        // startup — unknown phase is a data-integrity issue.
1369	        const LEGACY_COLLAPSE: Record<string, WritPhase> = {
1370	          ready: 'open',
1371	          active: 'open',
1372	          waiting: 'open',
1373	        };
1374	        const VALID_PHASES = new Set<WritPhase>([
1375	          'new', 'open', 'stuck', 'completed', 'failed', 'cancelled',
1376	        ]);
1377	
1378	        const allWrits = await writs.find({});
1379	        for (const row of allWrits) {
1380	          // Already migrated — skip (idempotent).
1381	          if (typeof (row as { phase?: unknown }).phase === 'string') continue;
1382	
1383	          const legacyStatus = (row as { status?: unknown }).status;
1384	          if (typeof legacyStatus !== 'string') {
1385	            throw new Error(
1386	              `[clerk] Migration: writ "${row.id}" has neither \`phase\` nor a string \`status\` field; cannot migrate (got ${legacyStatus === undefined ? 'undefined' : typeof legacyStatus}).`,
1387	            );
1388	          }
1389	
1390	          let nextPhase: WritPhase;
1391	          if (LEGACY_COLLAPSE[legacyStatus]) {
1392	            nextPhase = LEGACY_COLLAPSE[legacyStatus];
1393	          } else if (VALID_PHASES.has(legacyStatus as WritPhase)) {
1394	            nextPhase = legacyStatus as WritPhase;
1395	          } else {
1396	            throw new Error(
1397	              `[clerk] Migration: writ "${row.id}" has unrecognized status value "${legacyStatus}". Expected one of: ${[...VALID_PHASES].join(', ')} (or legacy: ${Object.keys(LEGACY_COLLAPSE).join(', ')}).`,
1398	            );
1399	          }
1400	
1401	          // Build a clean post-rename document — no `status` key, `phase`
1402	          // set. `updatedAt` is preserved exactly as stored (this is a
1403	          // storage-format change, not a logical edit).
1404	          const migrated: Record<string, unknown> = {};
1405	          for (const [k, v] of Object.entries(row)) {
1406	            if (k === 'status') continue;
1407	            migrated[k] = v;
1408	          }
1409	          migrated.phase = nextPhase;
1410	          await writs.put(migrated as WritDoc);
1411	        }
1412	
1413	        // ── One-shot migration: normalize link rows ──────────────────
1414	        // Two-pass flow per D7:
1415	        //   Pass 1 — scan every link row, group by (sourceId, targetId,
1416	        //     normalizedLabel). A group with multiple rows is a collision:
1417	        //     variant spellings that collapse to the same canonical form.
1418	        //   Pass 2 — per group, keep the row with the earliest createdAt;
1419	        //     warn and delete the younger siblings (older wins,
1420	        //     deterministic regardless of iteration order). Rewrite the
1421	        //     survivor's id and label to the canonical form and set
1422	        //     `kind = null` when absent.
1423	        //
1424	        // Safe to run inside start(): stacks only seals the CDC registry
1425	        // at phase:started (after every apparatus has started), so these
1426	        // writes don't lock out downstream apparatuses that register
1427	        // watchers in their own start(). Writes here fire no links-book
1428	        // watcher today but could in the future.
1429	        const allLinks = await links.find({});
1430	        const groups = new Map<string, WritLinkDoc[]>();
1431	        for (const row of allLinks) {
1432	          const normalized = normalizeLinkLabel(row.label);
1433	          const key = `${row.sourceId}:${row.targetId}:${normalized}`;
1434	          const bucket = groups.get(key) ?? [];
1435	          bucket.push(row);
1436	          groups.set(key, bucket);
1437	        }
1438	
1439	        for (const [canonicalId, bucket] of groups) {
1440	          // Sort by createdAt ascending — the first element is the oldest.
1441	          bucket.sort((a, b) => (a.createdAt < b.createdAt ? -1 : a.createdAt > b.createdAt ? 1 : 0));
1442	          const [survivor, ...losers] = bucket;
1443	          if (!survivor) continue;
1444	
1445	          for (const loser of losers) {
1446	            console.warn(
1447	              `[clerk] Link migration: collapsing duplicate link ` +
1448	                `"${loser.id}" into canonical "${canonicalId}" ` +
1449	                `(source="${loser.sourceId}", target="${loser.targetId}"); ` +
1450	                `older row kept, this one discarded.`,
1451	            );
1452	            await links.delete(loser.id);
1453	          }
1454	
1455	          const normalizedLabel = canonicalId.slice(
1456	            (survivor.sourceId.length + 1) + (survivor.targetId.length + 1),
1457	          );
1458	          const needsRewrite =
1459	            survivor.id !== canonicalId ||
1460	            survivor.label !== normalizedLabel ||
1461	            survivor.kind === undefined;
1462	
1463	          if (!needsRewrite) continue;
1464	
1465	          // The composite id is immutable — delete-then-put the survivor to
1466	          // replace it with the canonical document.
1467	          const migrated: WritLinkDoc = {
1468	            id: canonicalId,
1469	            sourceId: survivor.sourceId,
1470	            targetId: survivor.targetId,
1471	            label: normalizedLabel,
1472	            kind: survivor.kind ?? null,
1473	            createdAt: survivor.createdAt,
1474	          };
1475	          if (survivor.id !== canonicalId) {
1476	            await links.delete(survivor.id);
1477	          }
1478	          await links.put(migrated);
1479	        }
1480	
1481	        // ── One-shot migration: rename `spider.follows` → `depends-on` ──
1482	        //
1483	        // The dependency-link kind moved out of Spider's namespace
1484	        // (`spider.follows`) and onto the Clerk's substrate (`depends-on`)
1485	        // — see the `depends-on` declaration in this apparatus's
1486	        // `supportKit.linkKinds`. This pass rewrites every persisted link
1487	        // row that still carries the legacy kind so downstream readers
1488	        // (Spider's dispatch gate, the Reckoner, anyone querying
1489	        // `link.kind`) see the canonical name.
1490	        //
1491	        // The composite link id (`{src}:{tgt}:{normalized-label}`) is
1492	        // unaffected because the kind is not part of the id; `createdAt`
1493	        // and all other fields are preserved trivially via
1494	        // `links.patch(id, { kind })`. Idempotent: re-running on
1495	        // already-migrated data is a no-op.
1496	        const allLinksForKindMigration = await links.find({});
1497	        let renamed = 0;
1498	        for (const row of allLinksForKindMigration) {
1499	          if (row.kind === 'spider.follows') {
1500	            await links.patch(row.id, { kind: 'depends-on' });
1501	            renamed += 1;
1502	          }
1503	        }
1504	        if (renamed > 0) {
1505	          // eslint-disable-next-line no-console
1506	          console.log(
1507	            `[clerk] Link migration: renamed ${renamed} "spider.follows" rows to "depends-on".`,
1508	          );
1509	        }
1510	      },
1511	    },
1512	  };
1513	}
