1	/**
2	 * The Stacks — public API types.
3	 *
4	 * These types form the contract between The Stacks apparatus and all
5	 * consuming plugins. No SQLite types, no implementation details.
6	 *
7	 * See: docs/specification.md
8	 */
9	
10	// ── Plugin config ────────────────────────────────────────────────────
11	
12	/** Plugin configuration stored at guild.json["stacks"]. */
13	export interface StacksConfig {
14	  /**
15	   * Automatically apply pending database migrations when the Books are opened.
16	   * Defaults to `true` when not specified.
17	   */
18	  autoMigrate?: boolean;
19	}
20	
21	// Augment GuildConfig so `guild().config('stacks')` returns StacksConfig
22	// without requiring a manual type parameter at the call site.
23	declare module '@shardworks/nexus-core' {
24	  interface GuildConfig {
25	    stacks?: StacksConfig;
26	  }
27	}
28	
29	// ── Document model ────────────────────────────────────────────────────
30	
31	/** Every document stored in a book must satisfy this constraint. */
32	export type BookEntry = { id: string } & Record<string, unknown>;
33	
34	// ── Book schema declaration ───────────────────────────────────────────
35	
36	/**
37	 * Schema declaration for a single book in a kit's `books` contribution.
38	 *
39	 * `indexes` is a list of fields to create efficient query indexes for.
40	 * Field names use plain notation ('status') or dot-notation for nested
41	 * fields ('parent.id'). The Stacks translates internally.
42	 */
43	export interface BookSchema {
44	  indexes?: (string | string[])[];
45	}
46	
47	// ── Query language ────────────────────────────────────────────────────
48	
49	export type Scalar = string | number | boolean | null;
50	
51	export type WhereCondition =
52	  | [field: string, op: '=' | '!=', value: Scalar]
53	  | [field: string, op: '>' | '>=' | '<' | '<=', value: number | string]
54	  | [field: string, op: 'LIKE', value: string]
55	  | [field: string, op: 'IN', value: Scalar[]]
56	  | [field: string, op: 'IS NULL' | 'IS NOT NULL'];
57	
58	export type WhereClause = WhereCondition[];
59	
60	export type OrderEntry = [field: string, direction: 'asc' | 'desc'];
61	export type OrderBy = OrderEntry | OrderEntry[];
62	
63	export type Pagination =
64	  | { limit: number; offset?: number }
65	  | { limit?: never; offset?: never };
66	
67	export type BookQuery = {
68	  where?: WhereClause | { or: WhereClause[] };
69	  orderBy?: OrderBy;
70	} & Pagination;
71	
72	export type ListOptions = {
73	  orderBy?: OrderBy;
74	} & Pagination;
75	
76	// ── Book handles ──────────────────────────────────────────────────────
77	
78	/** Read-only view of a book — returned by `readBook()` for cross-plugin access. */
79	export interface ReadOnlyBook<T extends BookEntry> {
80	  get(id: string): Promise<T | null>;
81	  find(query: BookQuery): Promise<T[]>;
