1	/**
2	 * Query translation — public WhereClause tuples → InternalQuery.
3	 *
4	 * Validates field names against a safe allowlist, then maps the
5	 * user-facing operator strings to the backend's internal enum.
6	 */
7	
8	import type { BookQuery, WhereClause, WhereCondition } from './types.ts';
9	import type { InternalCondition, InternalQuery } from './backend.ts';
10	import { normalizeOrderBy } from './field-utils.ts';
11	
12	// ── Field name validation ─────────────────────────────────────────────
13	
14	const SAFE_FIELD_RE = /^[A-Za-z0-9_.-]+$/;
15	
16	export function validateFieldName(field: string): string {
17	  if (!SAFE_FIELD_RE.test(field)) {
18	    throw new Error(`[stacks] Unsafe field name rejected: "${field}"`);
19	  }
20	  return field;
21	}
22	
23	// ── Condition translation ─────────────────────────────────────────────
24	
25	function translateCondition(cond: WhereCondition): InternalCondition {
26	  const field = validateFieldName(cond[0]);
27	  const op = cond[1];
28	
29	  switch (op) {
30	    case '=':        return { field, op: 'eq',  value: cond[2] };
31	    case '!=':       return { field, op: 'neq', value: cond[2] };
32	    case '>':        return { field, op: 'gt',  value: cond[2] as number | string };
33	    case '>=':       return { field, op: 'gte', value: cond[2] as number | string };
34	    case '<':        return { field, op: 'lt',  value: cond[2] as number | string };
35	    case '<=':       return { field, op: 'lte', value: cond[2] as number | string };
36	    case 'LIKE':     return { field, op: 'like', value: cond[2] };
37	    case 'IN':       return { field, op: 'in', values: cond[2] };
38	    case 'IS NULL':  return { field, op: 'isNull' };
39	    case 'IS NOT NULL': return { field, op: 'isNotNull' };
40	    default:
41	      throw new Error(`[stacks] Unknown operator: "${op as string}"`);
42	  }
43	}
44	
45	// ── Public translation ────────────────────────────────────────────────
46	
47	export function translateQuery(query: BookQuery): InternalQuery {
48	  // Only called for AND queries — OR queries are handled at the apparatus level
49	  const where = Array.isArray(query.where) ? query.where : undefined;
50	
51	  // Normalize orderBy via shared utility, then validate field names
52	  // at the untrusted-input boundary.
53	  let orderBy: Array<{ field: string; dir: 'asc' | 'desc' }> | undefined;
54	  if (query.orderBy) {
55	    orderBy = normalizeOrderBy(query.orderBy);
56	    for (const entry of orderBy) {
57	      validateFieldName(entry.field);
58	    }
59	  }
60	
61	  return {
62	    where: where?.map(translateCondition),
63	    orderBy,
64	    limit: query.limit,
65	    offset: query.offset,
66	  };
67	}
68	
69	/**
70	 * Translate a WhereClause into conditions only (no pagination fields).
71	 * OR clauses are handled at the apparatus level — this only handles AND.
72	 */
73	export function translateWhereClause(
74	  where?: WhereClause | { or: WhereClause[] },
75	): { where?: InternalCondition[] } {
76	  if (!where) return {};
77	  // Only handles AND clauses — OR is handled at the apparatus level
78	  if (!Array.isArray(where)) return {};
79	  if (where.length === 0) return {};
80	  return { where: where.map(translateCondition) };
81	}
