191	  async runTransaction<R>(fn: (tx: TransactionContext) => Promise<R>): Promise<R> {
192	    // If already in a transaction, just run (no nesting — flattened)
193	    if (this.activeTx) {
194	      const txCtx = this.createTransactionContext();
195	      return fn(txCtx);
196	    }
197	
198	    // Phase-2 cross-transaction re-entry bound (gate-entry, D5/D6).
199	    // If we're being entered from within a Phase-2 handler chain that
200	    // has already accumulated MAX_PHASE2_REENTRY_DEPTH hops, refuse to
201	    // open a new backend transaction so the offending handler write is
202	    // rejected (D10 partial-commit) and the chain terminates loud.
203	    // The throw fires before the try/catch below so the existing
204	    // rollback path — which only handles tx-level failures — is not
205	    // engaged for a transaction that was never opened.
206	    if (this.phase2Depth >= MAX_PHASE2_REENTRY_DEPTH) {
207	      throw new Phase2DepthExceededError(MAX_PHASE2_REENTRY_DEPTH);
208	    }
