395	  // ── Read operations ───────────────────────────────────────────────
396	
397	  doGet(ref: BookRef, id: string): BookEntry | null {
398	    if (this.activeTx) {
399	      return this.activeTx.backendTx.get(ref, id);
400	    }
401	    // Outside a transaction — use a throwaway read transaction
402	    const tx = this.backend.beginTransaction();
403	    try {
404	      const result = tx.get(ref, id);
