412	
413	  async doFind(ref: BookRef, query: BookQuery): Promise<BookEntry[]> {
414	    // Handle OR queries at the apparatus level
415	    if (query.where && !Array.isArray(query.where) && 'or' in query.where) {
416	      return this.doFindOr(ref, query);
417	    }
418	
419	    const internal = translateQuery(query as BookQuery & { where?: WhereClause });
420	    if (this.activeTx) {
421	      return this.activeTx.backendTx.find(ref, internal);
422	    }
423	    const tx = this.backend.beginTransaction();
424	    try {
425	      const result = tx.find(ref, internal);
426	      tx.commit();
427	      return result;
428	    } catch (err) {
429	      tx.rollback();
430	      throw err;
431	    }
432	  }
