434	  /**
435	   * OR queries: run each branch as a separate backend query, deduplicate
436	   * by id, re-sort, and paginate the merged result set.
437	   *
438	   * V1 trade-off: when called outside an active transaction, each branch
439	   * opens its own throwaway read transaction. For synchronous backends
440	   * like better-sqlite3, the data can't change between branches so this
441	   * is safe. A hypothetical async backend could see different snapshots
442	   * per branch, producing inconsistent results — a known limitation
443	   * documented in the spec's implementation notes.
444	   *
445	   * Performance note: each branch is a separate backend query. count()
446	   * with OR cannot use the backend's efficient count path since
447	   * deduplication requires knowing which IDs overlap. Acceptable for v1.
448	   */
449	  private async doFindOr(ref: BookRef, query: BookQuery): Promise<BookEntry[]> {
450	    const orClauses = (query.where as { or: WhereClause[] }).or;
451	
452	    if (orClauses.length === 0) return [];
453	
454	    const seen = new Set<string>();
455	    const merged: BookEntry[] = [];
456	
457	    const runBranch = (branch: WhereClause): BookEntry[] => {
458	      const branchQuery = translateQuery({ where: branch } as BookQuery & { where?: WhereClause });
459	      if (this.activeTx) {
460	        return this.activeTx.backendTx.find(ref, branchQuery);
461	      }
462	      const tx = this.backend.beginTransaction();
463	      try {
464	        const result = tx.find(ref, branchQuery);
465	        tx.commit();
466	        return result;
467	      } catch (err) {
468	        tx.rollback();
469	        throw err;
470	      }
471	    };
472	
473	    for (const branch of orClauses) {
474	      const results = runBranch(branch);
475	      for (const entry of results) {
476	        if (!seen.has(entry.id)) {
477	          seen.add(entry.id);
478	          merged.push(entry);
479	        }
480	      }
481	    }
482	
483	    // Apply sorting
484	    if (query.orderBy) {
485	      const orderEntries = normalizeOrderBy(query.orderBy);
486	      merged.sort((a, b) => compareByOrderEntries(a, b, orderEntries));
487	    }
488	
489	    // Apply pagination
490	    let result = merged;
491	    if (query.offset !== undefined) {
492	      result = result.slice(query.offset);
493	    }
494	    if (query.limit !== undefined) {
495	      result = result.slice(0, query.limit);
496	    }
497	
498	    return result;
499	  }
500	
501	  async doCount(ref: BookRef, where?: WhereClause | { or: WhereClause[] }): Promise<number> {
502	    // Handle OR queries — must deduplicate, so use doFindOr
503	    if (where && !Array.isArray(where) && 'or' in where) {
504	      const results = await this.doFindOr(ref, { where } as BookQuery);
505	      return results.length;
506	    }
507	
508	    const internal = translateWhereClause(where as WhereClause | undefined);
509	    if (this.activeTx) {
510	      return this.activeTx.backendTx.count(ref, internal);
511	    }
512	    const tx = this.backend.beginTransaction();
513	    try {
514	      const result = tx.count(ref, internal);
515	      tx.commit();
516	      return result;
517	    } catch (err) {
518	      tx.rollback();
519	      throw err;
520	    }
521	  }
522	
523	  private requireTx(): ActiveTransaction {
524	    if (!this.activeTx) {
525	      throw new Error('[stacks] Write operation outside transaction — this is a bug');
526	    }
527	    return this.activeTx;
528	  }
529	}
